  ('disabled-57f41407-moex-00148', 'disabled-57f41407', 'disabled-57f41407-moex-114-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲、乙相約互毆，2 人均受傷，並互提傷害告訴。關於甲、乙之罪責，下 列敘述何者正確？', '["甲、乙均成立傷害罪", "甲、乙均構成傷害罪，但均屬正當防衛", "甲、乙均構成傷害罪，但傷勢較重之一方為正當防衛", "甲、乙均構成傷害罪，且均屬正當防衛，但傷勢較輕之一方為防衛過當"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "d2124292ad0a", "answer_pdf_sha1": "f10b97dd76ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0309", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
