  ('disabled-57f41407-moex-00151', 'disabled-57f41407', 'disabled-57f41407-moex-113-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '下列文句「」中的成語，何者運用最恰當？', '["他是「一絲不苟」的人，一向粗心大意，所以做事常常出紕漏", "我們專業貼心的居家清潔服務，保證讓您的居室「充棟汗牛」", "他努力克服各種挑戰，最終達成任務，便「志得意滿」的笑了", "您的言論真是「拋磚引玉」，為我將來的研究提供了不少幫助"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:35+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
